(78, 265, 'लेखक का नाम क्या है?', '[\"\\u092a\\u094d\\u0930\\u0947\\u092e\\u091a\\u0902\\u0926\", \"\\u0930\\u093e\\u0939\\u0941\\u0932 \\u0938\\u093e\\u0902\\u0915\\u0943\\u0924\\u094d\\u092f\\u093e\\u092f\\u0928\", \"\\u092e\\u0939\\u093e\\u0926\\u0947\\u0935\\u0940 \\u0935\\u0930\\u094d\\u092e\\u093e\", \"\\u0939\\u091c\\u093e\\u0930\\u0940 \\u092a\\u094d\\u0930\\u0938\\u093e\\u0926 \\u0926\\u094d\\u0935\\u093f\\u0935\\u0947\\u0926\\u0940\"]', 0, 'दो बैलों की कथा के लेखक प्रेमचंद हैं।', '2026-03-18 04:56:14'),
(79, 265, 'दोनों बैलों के नाम क्या थे?', '[\"\\u0939\\u0940\\u0930\\u093e \\u0914\\u0930 \\u092e\\u094b\\u0924\\u0940\", \"\\u0938\\u094b\\u0928\\u093e \\u0914\\u0930 \\u0930\\u0942\\u092a\\u093e\", \"\\u0930\\u093e\\u091c\\u093e \\u0914\\u0930 \\u0930\\u093e\\u0928\\u0940\", \"\\u091c\\u092f \\u0914\\u0930 \\u0935\\u093f\\u091c\\u092f\"]', 0, 'बैलों के नाम हीरा और मोती थे।', '2026-03-18 04:56:14'),
(80, 268, 'శివతాండవం కవితా ఖండికను రచించినది ఎవరు?', '[\"\\u0c2a\\u0c41\\u0c1f\\u0c4d\\u0c1f\\u0c2a\\u0c30\\u0c4d\\u0c24\\u0c3f \\u0c28\\u0c3e\\u0c30\\u0c3e\\u0c2f\\u0c23\\u0c3e\\u0c1a\\u0c3e\\u0c30\\u0c4d\\u0c2f\\u0c41\\u0c32\\u0c41\", \"\\u0c36\\u0c4d\\u0c30\\u0c40\\u0c36\\u0c4d\\u0c30\\u0c40\", \"\\u0c26\\u0c47\\u0c35\\u0c41\\u0c32\\u0c2a\\u0c32\\u0c4d\\u0c32\\u0c3f\", \"\\u0c35\\u0c3f\\u0c36\\u0c4d\\u0c35\\u0c28\\u0c3e\\u0c25\"]', 0, 'పుట్టపర్తి నారాయణాచార్యులు దీనిని రచించారు.', '2026-03-18 04:56:14'),
(81, 261, 'పల్లెటూరి పిల్లగాడు పాఠ్యం ద్వారా కవి ఏమి తెలియజేశారు?', '[\"\\u0c2c\\u0c3e\\u0c32 \\u0c15\\u0c3e\\u0c30\\u0c4d\\u0c2e\\u0c3f\\u0c15 \\u0c35\\u0c4d\\u0c2f\\u0c35\\u0c38\\u0c4d\\u0c25\", \"\\u0c2a\\u0c32\\u0c4d\\u0c32\\u0c46 \\u0c05\\u0c02\\u0c26\\u0c3e\\u0c32\\u0c41\", \"\\u0c1a\\u0c26\\u0c41\\u0c35\\u0c41\", \"\\u0c06\\u0c1f\\u0c32\\u0c41\"]', 0, 'బాల కార్మిక వ్యవస్థ గురించి వివరించారు.', '2026-03-18 04:56:14'),
(82, 271, 'सूरदास के पदों में मुख्य रूप से किसकी भक्ति की गई है?', '[\"\\u0930\\u093e\\u092e\", \"\\u0915\\u0943\\u0937\\u094d\\u0923\", \"\\u0936\\u093f\\u0935\", \"\\u0935\\u093f\\u0937\\u094d\\u0923\\u0941\"]', 1, 'सूरदास कृष्ण के अनन्य भक्त थे।', '2026-03-18 04:56:14'),
(83, 274, 'మాతృభావన పాఠ్యభాగం ఏ ప్రక్రియకు చెందినది?', '[\"\\u0c15\\u0c35\\u0c3f\\u0c24\", \"\\u0c2a\\u0c26\\u0c4d\\u0c2f\\u0c02\", \"\\u0c35\\u0c1a\\u0c28\\u0c02\", \"\\u0c1a\\u0c3e\\u0c30\\u0c3f\\u0c24\\u0c4d\\u0c30\\u0c15 \\u0c15\\u0c3e\\u0c35\\u0c4d\\u0c2f\\u0c02\"]', 3, 'ఇది చారిత్రక కావ్య ప్రక్రియకు చెందినది.', '2026-03-18 04:56:14'),
(87, 255, 'कवि का नाम क्या है?', '[\"\\u0938\\u0942\\u0930\\u094d\\u092f\\u0915\\u093e\\u0902\\u0924 \\u0924\\u094d\\u0930\\u093f\\u092a\\u093e\\u0920\\u0940 \'\\u0928\\u093f\\u0930\\u093e\\u0932\\u093e\'\", \"\\u0938\\u0941\\u092e\\u093f\\u0924\\u094d\\u0930\\u093e\\u0928\\u0902\\u0926\\u0928 \\u092a\\u0902\\u0924\", \"\\u092e\\u0939\\u093e\\u0926\\u0947\\u0935\\u0940 \\u0935\\u0930\\u094d\\u092e\\u093e\", \"\\u091c\\u092f\\u0936\\u0902\\u0915\\u0930 \\u092a\\u094d\\u0930\\u0938\\u093e\\u0926\"]', 0, 'ध्वनि कविता के कवि सूर्यकांत त्रिपाठी \'निराला\' हैं।', '2026-03-18 05:01:14'),
(88, 255, 'अभी न होगा मेरा अंत - इस पंक्ति का क्या आशय है?', '[\"\\u0928\\u093f\\u0930\\u093e\\u0936\\u093e\", \"\\u0906\\u0924\\u094d\\u092e\\u0935\\u093f\\u0936\\u094d\\u0935\\u093e\\u0938\", \"\\u0915\\u094d\\u0930\\u094b\\u0927\", \"\\u0906\\u0932\\u0938\\u094d\\u092f\"]', 1, 'यह कवि के आत्मविश्वास को दर्शाता है।', '2026-03-18 05:01:14'),
(89, 260, 'మాతృభూమి పాఠ్యభాగ రచయిత ఎవరు?', '[\"\\u0c2e\\u0c41\\u0c26\\u0c4d\\u0c26\\u0c41\\u0c30\\u0c3e\\u0c2e\\u0c15\\u0c43\\u0c37\\u0c4d\\u0c23\\u0c2f\\u0c4d\\u0c2f\", \"\\u0c38\\u0c3f.\\u0c28\\u0c3e\\u0c30\\u0c3e\\u0c2f\\u0c23\\u0c30\\u0c46\\u0c21\\u0c4d\\u0c21\\u0c3f\", \"\\u0c36\\u0c4d\\u0c30\\u0c40\\u0c36\\u0c4d\\u0c30\\u0c40\", \"\\u0c17\\u0c41\\u0c30\\u0c1c\\u0c3e\\u0c21\"]', 0, 'మాతృభూమి పాఠ్యభాగ రచయిత ముద్దురామకృష్ణయ్య.', '2026-03-18 05:01:14'),
(90, 260, 'జన్మభూమి స్వర్గం కంటే మిన్న అని ఎవరు చెప్పారు?', '[\"\\u0c36\\u0c4d\\u0c30\\u0c40\\u0c30\\u0c3e\\u0c2e\\u0c41\\u0c21\\u0c41\", \"\\u0c36\\u0c4d\\u0c30\\u0c40\\u0c15\\u0c43\\u0c37\\u0c4d\\u0c23\\u0c41\\u0c21\\u0c41\", \"\\u0c05\\u0c30\\u0c4d\\u0c1c\\u0c41\\u0c28\\u0c41\\u0c21\\u0c41\", \"\\u0c2d\\u0c30\\u0c24\\u0c41\\u0c21\\u0c41\"]', 0, 'జననీ జన్మభూమిశ్చ స్వర్గాదపి గరీయసి అని శ్రీరాముడు చెప్పారు.', '2026-03-18 05:01:14'),
(91, 218, 'Smallest natural number is?', '[\"0\", \"1\", \"-1\", \"None\"]', 1, '1 starts the natural numbers.', '2026-03-18 05:01:14'),
(92, 218, 'Which of these is irrational?', '[\"3\", \"1.5\", \"\\u221a2\", \"4/5\"]', 2, '√2 cannot be written as p/q.', '2026-03-18 05:01:14'),
(93, 224, 'HCF of 6 and 20 is?', '[\"2\", \"4\", \"6\", \"10\"]', 0, '6=2x3, 20=2x2x5. HCF is 2.', '2026-03-18 05:01:14'),
(94, 224, 'LCM of 6 and 20 is?', '[\"20\", \"40\", \"60\", \"120\"]', 2, 'LCM is 60.', '2026-03-18 05:01:14'),
